mapper.sql:
WITH answer_union AS ( SELECT pd.create_time AS answer_time, 'PRACTICE' AS source, pr.id AS record_id, pr.user_id AS user_id, u.nickname AS user_nickname, u.phone AS user_phone, pr.bank_id AS bank_id, qb.name AS bank_name, q.id AS question_id, q.content AS question_content, pd.user_answer AS user_answer, q.answer AS correct_answer, pd.is_correct AS is_correct FROM practice_detail pd JOIN practice_record pr ON pd.record_id = pr.id JOIN user u ON pr.user_id = u.id AND u.deleted = 0 JOIN question q ON pd.question_id = q.id AND q.deleted = 0 LEFT JOIN question_bank qb ON pr.bank_id = qb.id AND qb.deleted = 0 WHERE pd.create_time >= #{startDateTime} AND pd.create_time < #{endDateTime}
UNION ALL
SELECT ea.create_time AS answer_time, 'EXAM' AS source, er.id AS record_id, er.user_id AS user_id, u.nickname AS user_nickname, u.phone AS user_phone, er.bank_id AS bank_id, qb.name AS bank_name, q.id AS question_id, q.content AS question_content, ea.user_answer AS user_answer, q.answer AS correct_answer, ea.is_correct AS is_correct FROM exam_answer ea JOIN exam_record er ON ea.exam_id = er.id JOIN user u ON er.user_id = u.id AND u.deleted = 0 JOIN question q ON ea.question_id = q.id AND q.deleted = 0 LEFT JOIN question_bank qb ON er.bank_id = qb.id AND qb.deleted = 0 WHERE ea.create_time >= #{startDateTime} AND ea.create_time < #{endDateTime} )

mapper.select:
SELECT
    (
        SELECT COUNT(DISTINCT user_id) FROM (
            SELECT u.id AS user_id
            FROM user u
            WHERE u.deleted = 0
              AND u.last_login_time IS NOT NULL
              AND u.last_login_time  >=  #{startDateTime}
              AND u.last_login_time  <  #{endDateTime}
            UNION
            SELECT pr.user_id
            FROM practice_record pr
            WHERE pr.create_time  >=  #{startDateTime}
              AND pr.create_time  <  #{endDateTime}
            UNION
            SELECT pr.user_id
            FROM practice_detail pd
            JOIN practice_record pr ON pd.record_id = pr.id
            WHERE pd.create_time  >=  #{startDateTime}
              AND pd.create_time  <  #{endDateTime}
            UNION
            SELECT er.user_id
            FROM exam_record er
            WHERE (er.create_time  >=  #{startDateTime} AND er.create_time  <  #{endDateTime})
               OR (er.end_time IS NOT NULL AND er.end_time  >=  #{startDateTime} AND er.end_time  <  #{endDateTime})
            UNION
            SELECT er.user_id
            FROM exam_answer ea
            JOIN exam_record er ON ea.exam_id = er.id
            WHERE ea.create_time  >=  #{startDateTime}
              AND ea.create_time  <  #{endDateTime}
            UNION
            SELECT acl.user_id
            FROM ai_call_log acl
            WHERE acl.call_type = 'USER'
              AND acl.user_id IS NOT NULL
              AND acl.create_time  >=  #{startDateTime}
              AND acl.create_time  <  #{endDateTime}
            UNION
            SELECT f.user_id
            FROM favorite f
            WHERE f.create_time  >=  #{startDateTime}
              AND f.create_time  <  #{endDateTime}
        ) active_users
    ) AS activeUsers,
    (
        SELECT COUNT(*)
        FROM user u
        WHERE u.deleted = 0
          AND u.last_login_time IS NOT NULL
          AND u.last_login_time  >=  #{startDateTime}
          AND u.last_login_time  <  #{endDateTime}
    ) AS loginUsers,
    (
        SELECT COUNT(DISTINCT user_id) FROM (
            SELECT pr.user_id
            FROM practice_record pr
            WHERE pr.create_time  >=  #{startDateTime}
              AND pr.create_time  <  #{endDateTime}
            UNION
            SELECT pr.user_id
            FROM practice_detail pd
            JOIN practice_record pr ON pd.record_id = pr.id
            WHERE pd.create_time  >=  #{startDateTime}
              AND pd.create_time  <  #{endDateTime}
        ) practice_users
    ) AS practiceUsers,
    (
        SELECT COUNT(*)
        FROM practice_detail pd
        WHERE pd.create_time  >=  #{startDateTime}
          AND pd.create_time  <  #{endDateTime}
    ) AS practiceAnswers,
    (
        SELECT COUNT(DISTINCT user_id) FROM (
            SELECT er.user_id
            FROM exam_record er
            WHERE (er.create_time  >=  #{startDateTime} AND er.create_time  <  #{endDateTime})
               OR (er.end_time IS NOT NULL AND er.end_time  >=  #{startDateTime} AND er.end_time  <  #{endDateTime})
            UNION
            SELECT er.user_id
            FROM exam_answer ea
            JOIN exam_record er ON ea.exam_id = er.id
            WHERE ea.create_time  >=  #{startDateTime}
              AND ea.create_time  <  #{endDateTime}
        ) exam_users
    ) AS examUsers,
    (
        SELECT COUNT(*)
        FROM exam_answer ea
        WHERE ea.create_time  >=  #{startDateTime}
          AND ea.create_time  <  #{endDateTime}
    ) AS examAnswers,
    (
        SELECT COUNT(DISTINCT acl.user_id)
        FROM ai_call_log acl
        WHERE acl.call_type = 'USER'
          AND acl.user_id IS NOT NULL
          AND acl.create_time  >=  #{startDateTime}
          AND acl.create_time  <  #{endDateTime}
    ) AS aiUsers,
    (
        SELECT COUNT(DISTINCT f.user_id)
        FROM favorite f
        WHERE f.create_time  >=  #{startDateTime}
          AND f.create_time  <  #{endDateTime}
    ) AS favoriteUsers

SELECT u.id AS userId, u.nickname AS userNickname, u.phone AS userPhone, u.avatar AS userAvatar, GREATEST( COALESCE(login_agg.last_active_time, '1970-01-01 00:00:00'), COALESCE(practice_agg.last_active_time, '1970-01-01 00:00:00'), COALESCE(exam_agg.last_active_time, '1970-01-01 00:00:00'), COALESCE(ai_agg.last_active_time, '1970-01-01 00:00:00'), COALESCE(favorite_agg.last_active_time, '1970-01-01 00:00:00') ) AS lastActiveTime, COALESCE(login_agg.login_count, 0) AS loginCount, COALESCE(practice_agg.practice_record_count, 0) AS practiceRecordCount, COALESCE(practice_agg.practice_answer_count, 0) AS practiceAnswerCount, COALESCE(exam_agg.exam_record_count, 0) AS examRecordCount, COALESCE(exam_agg.exam_answer_count, 0) AS examAnswerCount, COALESCE(ai_agg.ai_call_count, 0) AS aiCallCount, COALESCE(favorite_agg.favorite_count, 0) AS favoriteCount, ( COALESCE(login_agg.login_count, 0) + COALESCE(practice_agg.practice_record_count, 0) + COALESCE(practice_agg.practice_answer_count, 0) + COALESCE(exam_agg.exam_record_count, 0) + COALESCE(exam_agg.exam_answer_count, 0) + COALESCE(ai_agg.ai_call_count, 0) + COALESCE(favorite_agg.favorite_count, 0) ) AS totalActionCount FROM active_user_ids au JOIN user u ON u.id = au.user_id AND u.deleted = 0 LEFT JOIN login_agg ON login_agg.user_id = au.user_id LEFT JOIN practice_agg ON practice_agg.user_id = au.user_id LEFT JOIN exam_agg ON exam_agg.user_id = au.user_id LEFT JOIN ai_agg ON ai_agg.user_id = au.user_id LEFT JOIN favorite_agg ON favorite_agg.user_id = au.user_id
AND (u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY totalActionCount DESC, lastActiveTime DESC, u.id DESC LIMIT #{offset}, #{pageSize}


SELECT COUNT(*)
FROM answer_union


        AND (
            user_nickname LIKE CONCAT('%', #{keyword}, '%')
            OR user_phone LIKE CONCAT('%', #{keyword}, '%')
            OR bank_name LIKE CONCAT('%', #{keyword}, '%')
            OR question_content LIKE CONCAT('%', #{keyword}, '%')
            OR CAST(question_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%')
        )


        AND bank_id = #{bankId}


        AND source = #{source}




                AND is_correct IS NULL


                AND is_correct = #{result}




        AND user_id = #{userId}

SELECT answer_time AS answerTime, source AS source, record_id AS recordId, user_id AS userId, user_nickname AS userNickname, user_phone AS userPhone, bank_id AS bankId, bank_name AS bankName, question_id AS questionId, question_content AS questionContent, user_answer AS userAnswer, correct_answer AS correctAnswer, is_correct AS isCorrect FROM answer_union
AND ( user_nickname LIKE CONCAT('%', #{keyword}, '%') OR user_phone LIKE CONCAT('%', #{keyword}, '%') OR bank_name LIKE CONCAT('%', #{keyword}, '%') OR question_content LIKE CONCAT('%', #{keyword}, '%') OR CAST(question_id AS CHAR) LIKE CONCAT('%', #{keyword}, '%') )
AND bank_id = #{bankId}
AND source = #{source}
AND is_correct IS NULL
AND is_correct = #{result}
AND user_id = #{userId}
ORDER BY answer_time DESC, record_id DESC, question_id DESC LIMIT #{offset}, #{pageSize}
